import numpy as np
from app.strategy.base import BaseStrategy


class VAABreadthVolTargetStrategy(BaseStrategy):
    name = 'VAA Breadth + Vol Targeting'
    multi_asset = True

    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.params = {
            'rebalance_freq': 21,
            'target_vol': 0.15,
            'vol_lookback': 21,
            'max_alloc': 0.95,
        }
        self._last_positions = {}

    def _vaa_score(self, prices, i):
        """VAA momentum score: 12*r1m + 4*r3m + 2*r6m + r12m"""
        if i < 252:
            return None
        p_now = float(prices.iloc[i])
        if p_now <= 0:
            return None
        score = 0.0
        for period, weight in [(21, 12), (63, 4), (126, 2), (252, 1)]:
            idx = i - period
            if idx < 0:
                return None
            p_past = float(prices.iloc[idx])
            if p_past <= 0:
                return None
            score += weight * (p_now / p_past - 1.0)
        return score

    def _realized_vol(self, prices, i, lookback):
        """Annualized realized vol from daily returns"""
        if i < lookback + 2:
            return None
        slice_ = prices.iloc[i - lookback - 1:i + 1]
        rets = slice_.pct_change().dropna()
        if len(rets) < lookback // 2:
            return None
        return float(rets.std() * np.sqrt(252))

    def generate_signals(self, data: dict) -> dict:
        all_syms = list(data.keys())
        n_bars = len(data[all_syms[0]].index)
        index = data[all_syms[0]].index

        sig_arr = {sym: np.zeros(n_bars, dtype=float) for sym in all_syms}
        sz_arr = {sym: np.zeros(n_bars, dtype=float) for sym in all_syms}

        offensives = [s for s in ['QQQ', 'SPY', 'EFA', 'IWM'] if s in data]
        defensives = [s for s in ['TLT', 'GLD', 'AGG'] if s in data]

        if not offensives or not defensives:
            return {
                sym: pd.DataFrame({'signal': sig_arr[sym], 'size_pct': sz_arr[sym]}, index=index)
                for sym in all_syms
            }

        min_bars = 253

        for i in range(min_bars, n_bars):
            if i % self.params['rebalance_freq'] != 0:
                continue

            off_scores = {}
            for sym in offensives:
                score = self._vaa_score(data[sym]['close'], i)
                if score is not None:
                    off_scores[sym] = score

            def_scores = {}
            for sym in defensives:
                score = self._vaa_score(data[sym]['close'], i)
                if score is not None:
                    def_scores[sym] = score

            if not off_scores:
                continue

            # Breadth: fraction of offensive with positive VAA score
            n_positive = sum(1 for s in off_scores.values() if s > 0)
            breadth = n_positive / len(off_scores)

            best_off = max(off_scores.items(), key=lambda x: x[1])[0]
            best_def = max(def_scores.items(), key=lambda x: x[1])[0] if def_scores else 'TLT'

            total = self.params['max_alloc']
            off_alloc = breadth * total
            def_alloc = (1.0 - breadth) * total

            # Vol targeting: scale down when realized vol exceeds target
            vol_sym = 'SPY' if 'SPY' in data else offensives[0]
            rv = self._realized_vol(data[vol_sym]['close'], i, self.params['vol_lookback'])
            if rv and rv > 0:
                vol_scale = min(self.params['target_vol'] / rv, 1.0)
            else:
                vol_scale = 1.0

            off_alloc *= vol_scale
            def_alloc *= vol_scale

            target = {}
            if off_alloc > 0.005:
                target[best_off] = off_alloc
            if def_alloc > 0.005:
                target[best_def] = def_alloc

            current = self._last_positions
            for sym in all_syms:
                old_w = current.get(sym, 0.0)
                new_w = target.get(sym, 0.0)
                if old_w > 0 and new_w == 0:
                    sig_arr[sym][i] = -1
                elif old_w == 0 and new_w > 0:
                    sig_arr[sym][i] = 1
                    sz_arr[sym][i] = new_w
                elif old_w > 0 and new_w > 0 and abs(new_w - old_w) > 0.01:
                    sig_arr[sym][i] = 2
                    sz_arr[sym][i] = new_w

            self._last_positions = {s: w for s, w in target.items() if w > 0}

        return {
            sym: pd.DataFrame({'signal': sig_arr[sym], 'size_pct': sz_arr[sym]}, index=index)
            for sym in all_syms
        }
